const amqp = require('amqplib');
const processPayment = require('./paymentProcessor'); // Assume this is your payment processing logic

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = 'payment_events';

async function startConsumer() {
  try {
    const connection = await amqp.connect(RABBITMQ_URL);
    const channel = await connection.createChannel();

    await channel.assertQueue(QUEUE_NAME, { durable: true });

    console.log(`Waiting for messages in ${QUEUE_NAME}. To exit press CTRL+C`);

    channel.consume(QUEUE_NAME, async (msg) => {
      if (msg !== null) {
        try {
          const messageContent = msg.content.toString();
          const paymentData = JSON.parse(messageContent);

          // Validate the paymentData structure
          if (validatePaymentData(paymentData)) {
            await processPayment(paymentData);
            channel.ack(msg);
          } else {
            console.error('Invalid payment data structure:', paymentData);
            channel.nack(msg, false, false); // Discard the message
          }
        } catch (error) {
          console.error('Error processing message:', error);
          channel.nack(msg, false, false); // Discard the message
        }
      }
    });
  } catch (error) {
    console.error('Failed to start consumer:', error);
    process.exit(1);
  }
}

function validatePaymentData(data) {
  // Implement validation logic
  // Example: Check for required fields and data types
  return (
    typeof data === 'object' &&
    typeof data.amount === 'number' &&
    typeof data.currency === 'string' &&
    typeof data.userId === 'string'
  );
}

startConsumer();